import { useState } from "react";

const FAQS = [
  { q: "Gibt es eine kostenlose Testphase?", a: "Ja, du kannst {{projectName}} 14 Tage lang vollständig kostenlos testen – ohne Kreditkarte und ohne Einschränkungen." },
  { q: "Wie funktioniert die Abrechnung?", a: "Wir rechnen monatlich oder jährlich ab. Bei jährlicher Zahlung erhältst du zwei Monate gratis. Du kannst jederzeit kündigen." },
  { q: "Kann ich meinen Plan wechseln?", a: "Ja, jederzeit. Upgrades werden sofort wirksam und anteilig abgerechnet. Downgrades greifen zum nächsten Abrechnungszeitraum." },
  { q: "Wo werden meine Daten gespeichert?", a: "Alle Daten werden ausschließlich auf Servern in der EU gespeichert. Wir sind DSGVO-konform und führen regelmäßige Audits durch." },
  { q: "Bietet ihr einen dedizierten Support?", a: "Im Enterprise-Plan erhältst du einen persönlichen Ansprechpartner. Alle anderen Pläne haben Zugang zu unserem Priority-Support-Team." },
];

export default function FaqAccordion01() {
  const [open, setOpen] = useState<number | null>(null);
  return (
    <section id="faq" className="bg-slate-50 px-6 py-24">
      <div className="mx-auto max-w-3xl">
        <h2 className="text-center text-3xl font-extrabold text-slate-900">Häufige Fragen</h2>
        <p className="mt-3 text-center text-slate-500">Nicht dabei? Schreib uns – wir helfen gerne.</p>
        <div className="mt-10 space-y-3">
          {FAQS.map((faq, i) => (
            <div
              key={i}
              className="overflow-hidden rounded-2xl border border-slate-200 bg-white shadow-sm"
            >
              <button
                className="flex w-full items-center justify-between px-6 py-4 text-left text-sm font-semibold text-slate-900 hover:bg-slate-50"
                onClick={() => setOpen(open === i ? null : i)}
              >
                <span>{faq.q}</span>
                <span className={`text-slate-400 transition-transform duration-300 ${open === i ? "rotate-45" : ""}`}>+</span>
              </button>
              {open === i && (
                <div className="px-6 pb-5 text-sm text-slate-600 leading-relaxed border-t border-slate-100 pt-3">
                  {faq.a.replace("{{projectName}}", "{{projectName}}")}
                </div>
              )}
            </div>
          ))}
        </div>
      </div>
    </section>
  );
}

